#!/usr/bin/env python3
"""
Generates missing translations for ALL 15 languages.
Reads existing JSONs, adds missing translations, writes updated JSONs.
"""
import json
import os

TRANSLATIONS_DIR = "translations"

# Load all source strings
with open("all_strings.json", "r") as f:
    ALL_STRINGS = json.load(f)

def merge_translations(locale, new_translations):
    """Merge new translations into existing JSON file."""
    path = os.path.join(TRANSLATIONS_DIR, f"{locale}.json")
    with open(path, "r") as f:
        existing = json.load(f)
    
    added = 0
    for key, value in new_translations.items():
        if key not in existing:
            existing[key] = value
            added += 1
    
    with open(path, "w") as f:
        json.dump(existing, f, ensure_ascii=False, indent=2)
    
    # Check coverage
    covered = sum(1 for s in ALL_STRINGS if s in existing)
    print(f"  {locale}: added {added} new, total coverage: {covered}/{len(ALL_STRINGS)}")
    return existing

# Strings that are code/numbers and should remain the same across all languages
KEEP_SAME = {}
for s in ALL_STRINGS:
    # Numbers
    if s in ("0.01", "0.05", "0.10", "0.50", ".95", ".99", "1.00"):
        KEEP_SAME[s] = s
    # Pure PHP code examples
    elif s == '$parent_description . " | " . $value':
        KEEP_SAME[s] = s
    elif s == "$value * 1.21":
        KEEP_SAME[s] = s
    # URLs
    elif s == "https://example.com/products.xml":
        KEEP_SAME[s] = s
    # Technical patterns
    elif s == "{attribute1}→{value1}":
        KEEP_SAME[s] = s

print(f"Total source strings: {len(ALL_STRINGS)}")
print(f"Strings kept same (code/numbers): {len(KEEP_SAME)}")
print()

